async function run(params, api) {
  var target = params.target;
  var type = params.type || 'all';
  var result = {};
  if (type === 'dns' || type === 'all') {
    try {
      api.log('DNS lookup: ' + target);
      var dnsRaw = await api.httpGet('https://dns.google/resolve?name=' + encodeURIComponent(target) + '&type=A');
      var dns = JSON.parse(dnsRaw);
      result.dns_a = dns.Answer ? dns.Answer.map(function(a) { return { name: a.name, type: a.type, ttl: a.TTL, data: a.data }; }) : [];
      var dnsRawMx = await api.httpGet('https://dns.google/resolve?name=' + encodeURIComponent(target) + '&type=MX');
      var dnsMx = JSON.parse(dnsRawMx);
      result.dns_mx = dnsMx.Answer ? dnsMx.Answer.map(function(a) { return { data: a.data }; }) : [];
    } catch (e) {
      result.dns_error = String(e).slice(0, 200);
    }
  }
  if (type === 'ip' || type === 'all') {
    try {
      var ipTarget = target;
      if (result.dns_a && result.dns_a.length > 0) ipTarget = result.dns_a[0].data;
      api.log('IP lookup: ' + ipTarget);
      var ipRaw = await api.httpGet('http://ip-api.com/json/' + encodeURIComponent(ipTarget) + '?fields=status,country,regionName,city,isp,org,as,query');
      result.ip_info = JSON.parse(ipRaw);
    } catch (e) {
      result.ip_error = String(e).slice(0, 200);
    }
  }
  return JSON.stringify(result, null, 2);
}
